import math
from pathlib import Path

import pytest
import yaml

import graph
from astar import a_star


FIXTURES = Path(__file__).parent / 'fixtures'


def _load(path):
    with open(path) as f:
        return yaml.safe_load(f)


def _build_graph(spec):
    G = graph.Graph(directed=spec.get('directed', False))
    vertices = {name: G.insert_vertex(name) for name in spec['nodes']}
    for source, dest, weight in spec['edges']:
        G.insert_edge(vertices[source], vertices[dest], weight)
    return G, vertices


def _path_elements(path):
    return None if path is None else [v.element() for v in path]


@pytest.mark.parametrize(
    'fixture_path',
    sorted(FIXTURES.glob('*.yaml')),
    ids=lambda p: p.stem,
)
def test_a_star_matches_fixture(fixture_path):
    spec = _load(fixture_path)
    G, vertices = _build_graph(spec)

    estimates = spec['heuristic']
    def heuristic(v):
        return estimates[v.element()]

    start = vertices[spec['start']]
    goal = vertices[spec['goal']]

    path, length = a_star(G, start, goal, heuristic)

    assert _path_elements(path) == spec['expected_path']
    if math.isinf(spec['expected_length']):
        assert math.isinf(length)
    else:
        assert length == pytest.approx(spec['expected_length'])
